import { cursor } from './cursor';
import { gamePaused } from './game';
import { cluesGrid as grid } from './gameManager'; // 接入新的领域管理器
import { derived } from 'svelte/store';

export const keyboardDisabled = derived(
	[cursor, grid, gamePaused],
	([$cursor, $grid, $gamePaused]) => {
		if ($cursor.x === null || $cursor.y === null) return true;
		if (!$grid || !$grid[$cursor.y]) return true;

		return $grid[$cursor.y][$cursor.x] !== 0 || $gamePaused;
	},
	false,
);
